import{c as i,Q as a,j as r,m as t}from"./chunks/framework.DpF7k2f3.js";const d=JSON.parse('{"title":"附录D 8周入行计划日历","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"zh/appendix/appendix-d.md","filePath":"zh/appendix/appendix-d.md","lastUpdated":1779672565000}'),n={name:"zh/appendix/appendix-d.md"};function o(s,l,g,h,e,u){return a(),r("div",null,[...l[0]||(l[0]=[t('<h1 id="附录d-8周入行计划日历" tabindex="-1">附录D 8周入行计划日历 <a class="header-anchor" href="#附录d-8周入行计划日历" aria-label="Permalink to &quot;附录D 8周入行计划日历&quot;">​</a></h1><h2 id="使用说明" tabindex="-1">使用说明 <a class="header-anchor" href="#使用说明" aria-label="Permalink to &quot;使用说明&quot;">​</a></h2><p>这是一份<strong>可直接照着执行</strong>的8周入行计划。我设计这份日历的原则是：</p><ol><li><strong>现实可行</strong>：每天5小时左右的学习时间（上午2h + 下午2h + 晚上1h），周末正常休息</li><li><strong>循序渐进</strong>：前两周打基础，中间四周学核心技能，后两周做项目和求职</li><li><strong>产出导向</strong>：每一天都有明确的产出目标，确保学到东西而不是假装学习</li><li><strong>弹性空间</strong>：每周留1天&quot;补漏日&quot;，处理没跟上的内容</li></ol><p><strong>标记说明</strong>：</p><ul><li>🔴 <strong>必须完成</strong>：这部分没搞定，后面就别往下走了</li><li>🟡 <strong>有余力再做</strong>：时间充裕时可以挑战，但不是必须的</li><li>⚡ <strong>补漏日</strong>：每周六专门处理之前没完成的内容</li></ul><p><strong>执行心态</strong>：计划赶不上变化是正常的，漏掉的内容在补漏日补上就行。学不会的地方多查文档、多问AI，别死磕。最好的学习是动手敲代码，看10遍不如敲1遍。</p><hr><h2 id="第1周-python速通与编程基础" tabindex="-1">第1周：Python速通与编程基础 <a class="header-anchor" href="#第1周-python速通与编程基础" aria-label="Permalink to &quot;第1周：Python速通与编程基础&quot;">​</a></h2><p>本周目标是让你快速具备Python编码能力，能够看懂和编写基础的AI应用代码。如果你已经有Python基础，可以跳过部分内容。</p><h3 id="day-1-周一" tabindex="-1">Day 1（周一） <a class="header-anchor" href="#day-1-周一" aria-label="Permalink to &quot;Day 1（周一）&quot;">​</a></h3><p><strong>上午（2h）：环境搭建 + Python基础语法扫盲</strong></p><ul><li>安装Anaconda（或直接用Python 3.10+）</li><li>配置VS Code或PyCharm开发环境</li><li>过一遍Python基础语法：变量、数据类型、运算符</li><li>🔴 <strong>必须完成</strong>：在VS Code里运行第一个<code>print(&quot;Hello, AI!&quot;)</code></li></ul><p><strong>下午（2h）：控制流与函数</strong></p><ul><li>学习if/else、for/while循环</li><li>函数的定义与调用</li><li>动手练习：写一个计算器函数，支持加减乘除</li><li>🔴 <strong>必须完成</strong>：完成计算器函数，能正确处理基本运算</li></ul><p><strong>晚上（1h）：复习 + 社区潜水</strong></p><ul><li>回顾今天学的代码，在脑子里跑一遍</li><li>浏览GitHub Trending上的Python项目（感受一下真实的Python代码长什么样）</li><li><strong>产出</strong>：把计算器函数上传到自己的GitHub仓库</li></ul><hr><h3 id="day-2-周二" tabindex="-1">Day 2（周二） <a class="header-anchor" href="#day-2-周二" aria-label="Permalink to &quot;Day 2（周二）&quot;">​</a></h3><p><strong>上午（2h）：数据结构进阶</strong></p><ul><li>列表、元组、字典、集合的常用操作</li><li>列表推导式（这个在AI代码里很常见）</li><li>字符串处理方法</li><li>🔴 <strong>必须完成</strong>：能用列表推导式写一个简单的数据筛选</li></ul><p><strong>下午（2h）：文件操作与异常处理</strong></p><ul><li>读写文本文件、JSON文件</li><li>try/except异常捕获</li><li>实战：用Python读取一个JSON配置文件</li><li>🔴 <strong>必须完成</strong>：能独立读取和解析JSON文件</li></ul><p><strong>晚上（1h）：看一个真实项目</strong></p><ul><li>在GitHub上找一个简单的Python项目（比如一个爬虫），读懂它的结构</li><li>感受一下真实项目是怎么组织代码的</li><li><strong>产出</strong>：记下你看到的项目结构，和你之前练手的代码对比</li></ul><hr><h3 id="day-3-周三" tabindex="-1">Day 3（周三） <a class="header-anchor" href="#day-3-周三" aria-label="Permalink to &quot;Day 3（周三）&quot;">​</a></h3><p><strong>上午（2h）：面向对象编程基础</strong></p><ul><li>类和对象的概念</li><li>__init__方法、实例属性、类属性</li><li>继承与多态（了解概念即可）</li><li>🔴 <strong>必须完成</strong>：能写一个简单的类，比如一个&quot;学生&quot;类</li></ul><p><strong>下午（2h）：模块与包</strong></p><ul><li>import语句的各种用法</li><li>pip安装第三方库</li><li>虚拟环境的使用</li><li>🔴 <strong>必须完成</strong>：能创建虚拟环境并安装使用第三方库</li></ul><p><strong>晚上（1h）：练习时间</strong></p><ul><li>在LeetCode简单题里挑2-3道练手（主要练读题和写代码的能力）</li><li><strong>产出</strong>：至少完成1道简单算法题</li></ul><hr><h3 id="day-4-周四" tabindex="-1">Day 4（周四） <a class="header-anchor" href="#day-4-周四" aria-label="Permalink to &quot;Day 4（周四）&quot;">​</a></h3><p><strong>上午（2h）：Python与AI相关的库</strong></p><ul><li>requests库：用Python发HTTP请求（AI API调用的基础）</li><li>json库：处理JSON数据</li><li>🔴 <strong>必须完成</strong>：能用requests库调用一个公开API（如天气API）</li></ul><p><strong>下午（2h）：异步编程入门</strong></p><ul><li>了解async/await的基本用法</li><li>为什么AI调用需要异步（因为API响应慢）</li><li>🟡 <strong>有余力再做</strong>：写一个简单的异步请求示例</li></ul><p><strong>晚上（1h）：整理笔记</strong></p><ul><li>整理本周学到的Python知识，画一张思维导图</li><li><strong>产出</strong>：用自己的语言写出Python最核心的10个知识点</li></ul><hr><h3 id="day-5-周五" tabindex="-1">Day 5（周五） <a class="header-anchor" href="#day-5-周五" aria-label="Permalink to &quot;Day 5（周五）&quot;">​</a></h3><p><strong>上午（2h）：Python阶段性实战</strong></p><ul><li>综合练习：写一个命令行小工具（比如一个待办事项管理）</li><li>把之前学的：文件读写、类、异常处理都用上</li><li>🔴 <strong>必须完成</strong>：完成一个可运行的命令行工具</li></ul><p><strong>下午（2h）：Git基础</strong></p><ul><li>Git的基本操作：add、commit、push、pull</li><li>GitHub创建仓库、提PR的基础流程</li><li>🔴 <strong>必须完成</strong>：把本周的练习代码都推送到GitHub</li></ul><p><strong>晚上（1h）：第一周复盘</strong></p><ul><li>对照目标检查完成情况</li><li>标记没掌握的地方</li><li><strong>产出</strong>：更新GitHub仓库的README，写上这周学了什么</li></ul><hr><h3 id="day-6-周六-⚡-补漏日" tabindex="-1">Day 6（周六）⚡ 补漏日 <a class="header-anchor" href="#day-6-周六-⚡-补漏日" aria-label="Permalink to &quot;Day 6（周六）⚡ 补漏日&quot;">​</a></h3><p>今天是本周的补漏日，用来处理之前没跟上的内容。</p><p><strong>上午（2h）：查漏补缺</strong></p><ul><li>重新过一遍本周的&quot;必须完成&quot;项</li><li>哪个没搞定就专门练哪个</li><li>🔴 <strong>必须完成</strong>：确保所有&quot;必须完成&quot;项都已完成</li></ul><p><strong>下午（2h）：社区学习</strong></p><ul><li>逛逛CSDN、知乎、AI相关的技术社区</li><li>看看别人分享的入行经验，有没有可以借鉴的</li><li>🟡 <strong>有余力再做</strong>：在社区回答1-2个Python基础问题</li></ul><hr><h3 id="day-7-周日-休息日" tabindex="-1">Day 7（周日）休息日 <a class="header-anchor" href="#day-7-周日-休息日" aria-label="Permalink to &quot;Day 7（周日）休息日&quot;">​</a></h3><p>休息，放松大脑。可以看看技术博客、刷刷科技新闻，保持对行业的关注，但不要硬学新东西。</p><hr><h2 id="第2周-大模型api调用与prompt工程" tabindex="-1">第2周：大模型API调用与Prompt工程 <a class="header-anchor" href="#第2周-大模型api调用与prompt工程" aria-label="Permalink to &quot;第2周：大模型API调用与Prompt工程&quot;">​</a></h2><p>本周目标是让你能熟练调用AI大模型的API，并掌握Prompt工程的实用技巧。这是AI应用开发最核心的基础技能。</p><h3 id="day-8-周一" tabindex="-1">Day 8（周一） <a class="header-anchor" href="#day-8-周一" aria-label="Permalink to &quot;Day 8（周一）&quot;">​</a></h3><p><strong>上午（2h）：大模型API概览</strong></p><ul><li>了解OpenAI API、Claude API、国产模型（文心/通义/智谱）的特点</li><li>申请一个API Key（建议先从OpenAI或Claude开始，有免费额度）</li><li>🔴 <strong>必须完成</strong>：成功调用一次API，拿到返回结果</li></ul><p><strong>下午（2h）：Python调用AI API</strong></p><ul><li>用requests或openai库调用API</li><li>理解system、user、assistant消息角色</li><li>写一个最简单的对话程序</li><li>🔴 <strong>必须完成</strong>：能实现一个本地AI对话程序</li></ul><p><strong>晚上（1h）：阅读官方文档</strong></p><ul><li>快速浏览OpenAI或Claude的API文档</li><li>记住几个核心参数：temperature、max_tokens、model</li><li><strong>产出</strong>：用自己的话写出这些参数的作用</li></ul><hr><h3 id="day-9-周二" tabindex="-1">Day 9（周二） <a class="header-anchor" href="#day-9-周二" aria-label="Permalink to &quot;Day 9（周二）&quot;">​</a></h3><p><strong>上午（2h）：Prompt工程核心技巧</strong></p><ul><li>Zero-shot、Few-shot提示技巧</li><li>结构化输出（JSON格式）</li><li>🔴 <strong>必须完成</strong>：能让AI按指定格式返回JSON</li></ul><p><strong>下午（2h）：高级Prompt技巧</strong></p><ul><li>Chain of Thought（思维链）：让AI分步骤思考</li><li>prompt模板化：如何设计可复用的prompt</li><li>🟡 <strong>有余力再做</strong>：实现一个简单的prompt模板引擎</li></ul><p><strong>晚上（1h）：实战练习</strong></p><ul><li>给AI设计5个不同的prompt，对比效果</li><li><strong>产出</strong>：记录最佳prompt和效果分析</li></ul><hr><h3 id="day-10-周三" tabindex="-1">Day 10（周三） <a class="header-anchor" href="#day-10-周三" aria-label="Permalink to &quot;Day 10（周三）&quot;">​</a></h3><p><strong>上午（2h）：Token与成本管理</strong></p><ul><li>什么是Token，怎么计算</li><li>如何控制API调用成本</li><li>上下文窗口的限制</li><li>🔴 <strong>必须完成</strong>：能计算一段文本的Token数</li></ul><p><strong>下午（2h）：对话历史管理</strong></p><ul><li>多轮对话的实现方式</li><li>历史消息的压缩技巧</li><li>写一个带记忆的对话程序</li><li>🔴 <strong>必须完成</strong>：能实现5轮以上上下文记忆的对话</li></ul><p><strong>晚上（1h）：优化对话质量</strong></p><ul><li>测试不同的temperature值对输出的影响</li><li>找到适合自己场景的最佳参数组合</li><li><strong>产出</strong>：记录不同参数设置下的输出差异</li></ul><hr><h3 id="day-11-周四" tabindex="-1">Day 11（周四） <a class="header-anchor" href="#day-11-周四" aria-label="Permalink to &quot;Day 11（周四）&quot;">​</a></h3><p><strong>上午（2h）：Function Calling / Tool Use</strong></p><ul><li>什么是Function Calling</li><li>怎么定义工具函数</li><li>AI怎么决定调用哪个函数</li><li>🔴 <strong>必须完成</strong>：能让AI调用你定义的工具函数</li></ul><p><strong>下午（2h）：Function Calling实战</strong></p><ul><li>做一个天气查询工具（定义函数，AI调用获取天气）</li><li>做一个计算器工具</li><li>🔴 <strong>必须完成</strong>：完成至少一个可用的Function Calling示例</li></ul><p><strong>晚上（1h）：扩展练习</strong></p><ul><li>给自己设计一个需要调用多个工具的场景</li><li>🟡 <strong>有余力再做</strong>：实现一个带3个以上工具的Agent雏形</li></ul><hr><h3 id="day-12-周五" tabindex="-1">Day 12（周五） <a class="header-anchor" href="#day-12-周五" aria-label="Permalink to &quot;Day 12（周五）&quot;">​</a></h3><p><strong>上午（2h）：Token节省技巧</strong></p><ul><li>摘要式压缩历史消息</li><li>只保留关键信息的技巧</li><li>成本监控与预算控制</li><li>🔴 <strong>必须完成</strong>：实现一个简单的历史消息压缩函数</li></ul><p><strong>下午（2h）：多模型对比</strong></p><ul><li>用同样的prompt测试不同模型的效果</li><li>分析各模型的优劣势</li><li>为后续选型积累经验</li><li>🔴 <strong>必须完成</strong>：完成至少3个模型的对比测试</li></ul><p><strong>晚上（1h）：第二周复盘</strong></p><ul><li>检查API调用和Prompt工程的掌握情况</li><li>整理常用的prompt模板</li><li><strong>产出</strong>：把本周的代码整理到GitHub，更新README</li></ul><hr><h3 id="day-13-周六-⚡-补漏日" tabindex="-1">Day 13（周六）⚡ 补漏日 <a class="header-anchor" href="#day-13-周六-⚡-补漏日" aria-label="Permalink to &quot;Day 13（周六）⚡ 补漏日&quot;">​</a></h3><p><strong>上午（2h）：查漏补缺</strong></p><ul><li>确保API调用、Prompt工程、Function Calling都能独立完成</li><li>补上之前标记的&quot;有余力再做&quot;项</li></ul><p><strong>下午（2h）：项目预热</strong></p><ul><li>想想第三周要做的RAG项目，你需要准备什么</li><li>开始收集一些你自己领域的知识库数据</li><li>🟡 <strong>有余力再做</strong>：设计RAG项目的架构草图</li></ul><hr><h3 id="day-14-周日-休息日" tabindex="-1">Day 14（周日）休息日 <a class="header-anchor" href="#day-14-周日-休息日" aria-label="Permalink to &quot;Day 14（周日）休息日&quot;">​</a></h3><p>休息日。可以看看AI相关的公众号、播客，了解行业动态。也可以逛逛Hugging Face、LangChain官网，看看别人在做什么有趣的项目。</p><hr><h2 id="第3周-rag核心概念与数据处理" tabindex="-1">第3周：RAG核心概念与数据处理 <a class="header-anchor" href="#第3周-rag核心概念与数据处理" aria-label="Permalink to &quot;第3周：RAG核心概念与数据处理&quot;">​</a></h2><p>本周目标是理解RAG（检索增强生成）的完整链路，并完成基础的数据处理和向量数据库操作。</p><h3 id="day-15-周一" tabindex="-1">Day 15（周一） <a class="header-anchor" href="#day-15-周一" aria-label="Permalink to &quot;Day 15（周一）&quot;">​</a></h3><p><strong>上午（2h）：RAG入门</strong></p><ul><li>什么是RAG，为什么需要RAG</li><li>RAG的核心组件：文档解析、切片、向量化、检索、生成</li><li>RAG vs Fine-tuning：什么时候用哪个</li><li>🔴 <strong>必须完成</strong>：能用自己的话解释RAG是什么</li></ul><p><strong>下午（2h）：文档解析与处理</strong></p><ul><li>不同格式文档的解析方法（PDF、TXT、Markdown、HTML）</li><li>用python-docx、PyPDF2等库处理文档</li><li>文本清洗与标准化</li><li>🔴 <strong>必须完成</strong>：能提取并清洗任意格式文档的文本内容</li></ul><p><strong>晚上（1h）：收集你的知识库</strong></p><ul><li>准备你想做RAG的数据源</li><li>可以是技术文档、产品手册、FAQ等</li><li><strong>产出</strong>：整理好至少一份可用的原始数据</li></ul><hr><h3 id="day-16-周二" tabindex="-1">Day 16（周二） <a class="header-anchor" href="#day-16-周二" aria-label="Permalink to &quot;Day 16（周二）&quot;">​</a></h3><p><strong>上午（2h）：文本切片策略</strong></p><ul><li>固定长度切片 vs 语义切片</li><li>重叠切片的技巧</li><li>切片大小对效果的影响</li><li>🔴 <strong>必须完成</strong>：实现多种切片策略，能对比效果</li></ul><p><strong>下午（2h）：Embedding模型</strong></p><ul><li>什么是文本向量化（Embedding）</li><li>主流Embedding模型对比（OpenAI、BGE、M3E等）</li><li>如何选择Embedding模型</li><li>🔴 <strong>必须完成</strong>：能对文本进行向量化</li></ul><p><strong>晚上（1h）：测试Embedding效果</strong></p><ul><li>写代码测试不同Embedding模型的效果</li><li>🟡 <strong>有余力再做</strong>：对比至少2个Embedding模型</li></ul><hr><h3 id="day-17-周三" tabindex="-1">Day 17（周三） <a class="header-anchor" href="#day-17-周三" aria-label="Permalink to &quot;Day 17（周三）&quot;">​</a></h3><p><strong>上午（2h）：向量数据库</strong></p><ul><li>主流向量数据库介绍（Milvus、ChromaDB、FAISS、Pinecone）</li><li>各数据库的适用场景</li><li>本地开发推荐ChromaDB或FAISS</li><li>🔴 <strong>必须完成</strong>：能安装并使用一个向量数据库</li></ul><p><strong>下午（2h）：向量数据库实战</strong></p><ul><li>创建向量数据库</li><li>插入向量数据</li><li>进行向量检索（相似度搜索）</li><li>🔴 <strong>必须完成</strong>：完成一个完整的向量存储和检索流程</li></ul><p><strong>晚上（1h）：优化检索效果</strong></p><ul><li>测试不同的相似度度量方式（余弦相似度、欧氏距离）</li><li><strong>产出</strong>：对比不同检索方式的效果</li></ul><hr><h3 id="day-18-周四" tabindex="-1">Day 18（周四） <a class="header-anchor" href="#day-18-周四" aria-label="Permalink to &quot;Day 18（周四）&quot;">​</a></h3><p><strong>上午（2h）：RAG检索优化</strong></p><ul><li>混合检索：关键词检索 + 向量检索</li><li>检索结果的重排序（Rerank）</li><li>HyDE等高级检索技巧</li><li>🔴 <strong>必须完成</strong>：实现混合检索</li></ul><p><strong>下午（2h）：上下文构建</strong></p><ul><li>如何把检索结果高效地拼接到Prompt中</li><li>上下文窗口的合理利用</li><li>去重与信息压缩</li><li>🔴 <strong>必须完成</strong>：能把检索结果组装成高质量的Prompt</li></ul><p><strong>晚上（1h）：完整RAG流程串讲</strong></p><ul><li>从头到尾走一遍RAG流程</li><li>🟡 <strong>有余力再做</strong>：记录每个环节的耗时和优化点</li></ul><hr><h3 id="day-19-周五" tabindex="-1">Day 19（周五） <a class="header-anchor" href="#day-19-周五" aria-label="Permalink to &quot;Day 19（周五）&quot;">​</a></h3><p><strong>上午（2h）：RAG效果评估</strong></p><ul><li>RAG评估指标（Context Precision、Answer Relevance等）</li><li>如何设计自己的评估集</li><li>用AI辅助评估（让AI评价AI的回答）</li><li>🔴 <strong>必须完成</strong>：能对RAG系统进行简单的效果评估</li></ul><p><strong>下午（2h）：RAG常见问题与解决</strong></p><ul><li>幻觉问题怎么缓解</li><li>检索不到相关内容怎么办</li><li>生成回答质量不稳定的处理方法</li><li>🔴 <strong>必须完成</strong>：能列举RAG的3个常见问题及解决方案</li></ul><p><strong>晚上（1h）：第三周复盘</strong></p><ul><li>整理RAG相关代码和笔记</li><li><strong>产出</strong>：把RAG基础代码整理好，准备第三周做完整项目</li></ul><hr><h3 id="day-20-周六-⚡-补漏日" tabindex="-1">Day 20（周六）⚡ 补漏日 <a class="header-anchor" href="#day-20-周六-⚡-补漏日" aria-label="Permalink to &quot;Day 20（周六）⚡ 补漏日&quot;">​</a></h3><p><strong>上午（2h）：查漏补缺</strong></p><ul><li>确保RAG全链路都能独立完成</li><li>把之前跳过的练习补上</li></ul><p><strong>下午（2h）：准备RAG项目</strong></p><ul><li>确定第四周要做的RAG项目主题</li><li>收集数据、整理需求</li><li>🟡 <strong>有余力再做</strong>：画出项目架构图</li></ul><hr><h3 id="day-21-周日-休息日" tabindex="-1">Day 21（周日）休息日 <a class="header-anchor" href="#day-21-周日-休息日" aria-label="Permalink to &quot;Day 21（周日）休息日&quot;">​</a></h3><p>休息日。可以看看LangChain或LlamaIndex的官方文档，了解它们是怎么封装RAG的。</p><hr><h2 id="第4周-rag项目实战-agent核心概念" tabindex="-1">第4周：RAG项目实战 + Agent核心概念 <a class="header-anchor" href="#第4周-rag项目实战-agent核心概念" aria-label="Permalink to &quot;第4周：RAG项目实战 + Agent核心概念&quot;">​</a></h2><p>本周目标是完成一个完整的RAG项目，并开始学习Agent的核心逻辑。</p><h3 id="day-22-周一" tabindex="-1">Day 22（周一） <a class="header-anchor" href="#day-22-周一" aria-label="Permalink to &quot;Day 22（周一）&quot;">​</a></h3><p><strong>上午（2h）：RAG项目规划</strong></p><ul><li>确定项目需求和目标用户</li><li>设计系统架构</li><li>选型（用什么模型、什么向量数据库、用什么框架）</li><li>🔴 <strong>必须完成</strong>：完成项目设计文档</li></ul><p><strong>下午（2h）：数据准备</strong></p><ul><li>按照项目需求处理数据</li><li>设计切片策略</li><li>生成向量并存入数据库</li><li>🔴 <strong>必须完成</strong>：完成数据处理和向量存储</li></ul><p><strong>晚上（1h）：继续数据处理</strong></p><ul><li>遇到问题查文档或问AI</li><li>🟡 <strong>有余力再做</strong>：实现自动化的数据更新机制</li></ul><hr><h3 id="day-23-周二" tabindex="-1">Day 23（周二） <a class="header-anchor" href="#day-23-周二" aria-label="Permalink to &quot;Day 23（周二）&quot;">​</a></h3><p><strong>上午（2h）：检索模块开发</strong></p><ul><li>实现向量检索</li><li>实现关键词检索</li><li>实现混合检索</li><li>🔴 <strong>必须完成</strong>：检索模块可以正常工作</li></ul><p><strong>下午（2h）：生成模块开发</strong></p><ul><li>构建Prompt模板</li><li>调用大模型生成回答</li><li>实现上下文管理</li><li>🔴 <strong>必须完成</strong>：生成模块可以正常工作</li></ul><p><strong>晚上（1h）：串联测试</strong></p><ul><li>把检索和生成串联起来</li><li>测试完整流程</li><li><strong>产出</strong>：完成一个基本的RAG demo</li></ul><hr><h3 id="day-24-周三" tabindex="-1">Day 24（周三） <a class="header-anchor" href="#day-24-周三" aria-label="Permalink to &quot;Day 24（周三）&quot;">​</a></h3><p><strong>上午（2h）：项目优化</strong></p><ul><li>检索效果优化</li><li>生成质量优化</li><li>响应速度优化</li><li>🔴 <strong>必须完成</strong>：完成至少一项核心优化</li></ul><p><strong>下午（2h）：项目包装</strong></p><ul><li>添加日志和监控</li><li>添加异常处理</li><li>编写README和使用说明</li><li>🔴 <strong>必须完成</strong>：项目代码整洁，有基本文档</li></ul><p><strong>晚上（1h）：部署尝试</strong></p><ul><li>试试把RAG服务部署到本地</li><li>🟡 <strong>有余力再做</strong>：部署到云服务器或使用ngrok暴露接口</li></ul><hr><h3 id="day-25-周四" tabindex="-1">Day 25（周四） <a class="header-anchor" href="#day-25-周四" aria-label="Permalink to &quot;Day 25（周四）&quot;">​</a></h3><p><strong>上午（2h）：Agent基础概念</strong></p><ul><li>什么是Agent，它和普通程序有什么区别</li><li>Agent的核心要素：感知、思考、行动</li><li>ReAct模式：推理 + 行动</li><li>🔴 <strong>必须完成</strong>：能用自己的话解释Agent是什么</li></ul><p><strong>下午（2h）：简单Agent实现</strong></p><ul><li>用Function Calling实现一个简单的Agent</li><li>Agent的决策循环</li><li>工具的定义与注册</li><li>🔴 <strong>必须完成</strong>：能实现一个带决策循环的简单Agent</li></ul><p><strong>晚上（1h）：Agent vs RAG</strong></p><ul><li>对比Agent和RAG的适用场景</li><li>什么情况下用RAG，什么情况下用Agent</li><li><strong>产出</strong>：画出RAG和Agent的边界图</li></ul><hr><h3 id="day-26-周五" tabindex="-1">Day 26（周五） <a class="header-anchor" href="#day-26-周五" aria-label="Permalink to &quot;Day 26（周五）&quot;">​</a></h3><p><strong>上午（2h）：Agent进阶模式</strong></p><ul><li>多种Agent模式：ReAct、Plan-and-Execute、AutoGPT模式</li><li>Agent的记忆管理</li><li>多Agent协作的概念</li><li>🔴 <strong>必须完成</strong>：了解3种以上的Agent模式</li></ul><p><strong>下午（2h）：Agent项目规划</strong></p><ul><li>想想第五周要做的Agent项目</li><li>确定项目需求</li><li>🔴 <strong>必须完成</strong>：完成Agent项目设计文档</li></ul><p><strong>晚上（1h）：第四周复盘</strong></p><ul><li>整理RAG项目和Agent学习成果</li><li><strong>产出</strong>：更新GitHub仓库，把这周的项目代码放上去</li></ul><hr><h3 id="day-27-周六-⚡-补漏日" tabindex="-1">Day 27（周六）⚡ 补漏日 <a class="header-anchor" href="#day-27-周六-⚡-补漏日" aria-label="Permalink to &quot;Day 27（周六）⚡ 补漏日&quot;">​</a></h3><p><strong>上午（2h）：RAG项目收尾</strong></p><ul><li>确保RAG项目完全可用</li><li>补上之前跳过的优化项</li></ul><p><strong>下午（2h）：Agent预热</strong></p><ul><li>预研第五周Agent项目需要的技术</li><li>开始收集相关资料</li></ul><hr><h3 id="day-28-周日-休息日" tabindex="-1">Day 28（周日）休息日 <a class="header-anchor" href="#day-28-周日-休息日" aria-label="Permalink to &quot;Day 28（周日）休息日&quot;">​</a></h3><p>休息日。可以看看OpenAI、Anthropic官方博客，了解Agent领域的最新进展。</p><hr><h2 id="第5周-langchain-langgraph框架实战" tabindex="-1">第5周：LangChain/LangGraph框架实战 <a class="header-anchor" href="#第5周-langchain-langgraph框架实战" aria-label="Permalink to &quot;第5周：LangChain/LangGraph框架实战&quot;">​</a></h2><p>本周目标是掌握LangChain或LangGraph框架，能用它快速开发AI应用。</p><h3 id="day-29-周一" tabindex="-1">Day 29（周一） <a class="header-anchor" href="#day-29-周一" aria-label="Permalink to &quot;Day 29（周一）&quot;">​</a></h3><p><strong>上午（2h）：LangChain概览</strong></p><ul><li>LangChain是什么，解决了什么问题</li><li>LangChain的核心组件：Model I/O、Retrieval、Chains、Agents、Memory</li><li>安装LangChain和相关依赖</li><li>🔴 <strong>必须完成</strong>：能成功安装LangChain并跑通Hello World</li></ul><p><strong>下午（2h）：Model I/O</strong></p><ul><li>LLMs和ChatModels的使用</li><li>Prompt模板的使用</li><li>Output Parsers（输出解析器）</li><li>🔴 <strong>必须完成</strong>：能用LangChain调用AI模型</li></ul><p><strong>晚上（1h）：文档练习</strong></p><ul><li>跟着LangChain官方文档做一个小例子</li><li><strong>产出</strong>：完成一个用LangChain调用的简单程序</li></ul><hr><h3 id="day-30-周二" tabindex="-1">Day 30（周二） <a class="header-anchor" href="#day-30-周二" aria-label="Permalink to &quot;Day 30（周二）&quot;">​</a></h3><p><strong>上午（2h）：LangChain检索</strong></p><ul><li>LangChain的Document Loader</li><li>Text Splitters的使用</li><li>Embeddings和VectorStores</li><li>🔴 <strong>必须完成</strong>：能用LangChain加载文档并进行切片</li></ul><p><strong>下午（2h）：LangChain RAG实战</strong></p><ul><li>用LangChain实现完整的RAG流程</li><li>各种检索器的使用</li><li>🔴 <strong>必须完成</strong>：用LangChain实现一个RAG应用</li></ul><p><strong>晚上（1h）：对比原生实现</strong></p><ul><li>把之前自己写的RAG代码用LangChain重写</li><li>🟡 <strong>有余力再做</strong>：对比两种实现的优缺点</li></ul><hr><h3 id="day-31-周三" tabindex="-1">Day 31（周三） <a class="header-anchor" href="#day-31-周三" aria-label="Permalink to &quot;Day 31（周三）&quot;">​</a></h3><p><strong>上午（2h）：LangChain Chains</strong></p><ul><li>LLMChain的使用</li><li>SequentialChain（顺序链）</li><li>自定义Chain</li><li>🔴 <strong>必须完成</strong>：能使用SequentialChain串联多个步骤</li></ul><p><strong>下午（2h）：LangChain Agents</strong></p><ul><li>Agent的核心概念</li><li>各种Agent类型（ReAct、OpenAI Functions等）</li><li>Tool的使用</li><li>🔴 <strong>必须完成</strong>：能用LangChain实现一个带工具调用的Agent</li></ul><p><strong>晚上（1h）：深入Agent开发</strong></p><ul><li>给Agent添加更多工具</li><li>测试Agent的决策能力</li><li>🟡 <strong>有余力再做</strong>：实现一个多工具Agent</li></ul><hr><h3 id="day-32-周四" tabindex="-1">Day 32（周四） <a class="header-anchor" href="#day-32-周四" aria-label="Permalink to &quot;Day 32（周四）&quot;">​</a></h3><p><strong>上午（2h）：LangGraph概念</strong></p><ul><li>LangGraph vs LangChain：什么时候用哪个</li><li>LangGraph的核心概念：State、Node、Edge</li><li>状态机的思维方式</li><li>🔴 <strong>必须完成</strong>：理解LangGraph的编程模型</li></ul><p><strong>下午（2h）：LangGraph实战</strong></p><ul><li>用LangGraph实现一个简单的Agent</li><li>实现ReAct模式的Agent</li><li>🔴 <strong>必须完成</strong>：用LangGraph实现一个可用的Agent</li></ul><p><strong>晚上（1h）：对比LangChain Agent</strong></p><ul><li>对比LangChain Agent和LangGraph Agent的区别</li><li><strong>产出</strong>：写出两种实现的适用场景</li></ul><hr><h3 id="day-33-周五" tabindex="-1">Day 33（周五） <a class="header-anchor" href="#day-33-周五" aria-label="Permalink to &quot;Day 33（周五）&quot;">​</a></h3><p><strong>上午（2h）：LangChain Memory</strong></p><ul><li>ConversationBufferMemory</li><li>ConversationSummaryMemory</li><li>在Agent中使用Memory</li><li>🔴 <strong>必须完成</strong>：给Agent添加记忆功能</li></ul><p><strong>下午（2h）：Callback与监控</strong></p><ul><li>LangChain的Callback机制</li><li>添加日志和监控</li><li>性能追踪</li><li>🔴 <strong>必须完成</strong>：能添加基本的监控日志</li></ul><p><strong>晚上（1h）：第五周复盘</strong></p><ul><li>整理LangChain/LangGraph相关代码</li><li><strong>产出</strong>：把框架相关代码整理到GitHub</li></ul><hr><h3 id="day-34-周六-⚡-补漏日" tabindex="-1">Day 34（周六）⚡ 补漏日 <a class="header-anchor" href="#day-34-周六-⚡-补漏日" aria-label="Permalink to &quot;Day 34（周六）⚡ 补漏日&quot;">​</a></h3><p><strong>上午（2h）：查漏补缺</strong></p><ul><li>确保LangChain和LangGraph都能独立使用</li><li>补上之前跳过的练习</li></ul><p><strong>下午（2h）：项目规划</strong></p><ul><li>规划第六周的综合项目</li><li>确定项目需求和技术栈</li><li>🟡 <strong>有余力再做</strong>：画出项目架构图</li></ul><hr><h3 id="day-35-周日-休息日" tabindex="-1">Day 35（周日）休息日 <a class="header-anchor" href="#day-35-周日-休息日" aria-label="Permalink to &quot;Day 35（周日）休息日&quot;">​</a></h3><p>休息日。可以看看LangChain、LangGraph的GitHub仓库，了解社区在做什么。</p><hr><h2 id="第6周-综合项目-llamaindex" tabindex="-1">第6周：综合项目 + LlamaIndex <a class="header-anchor" href="#第6周-综合项目-llamaindex" aria-label="Permalink to &quot;第6周：综合项目 + LlamaIndex&quot;">​</a></h2><p>本周目标是完成一个综合性的AI应用项目，并学习LlamaIndex作为补充。</p><h3 id="day-36-周一" tabindex="-1">Day 36（周一） <a class="header-anchor" href="#day-36-周一" aria-label="Permalink to &quot;Day 36（周一）&quot;">​</a></h3><p><strong>上午（2h）：项目启动</strong></p><ul><li>确定项目主题（建议做一个有实际价值的工具）</li><li>需求分析和详细设计</li><li>技术选型</li><li>🔴 <strong>必须完成</strong>：完成项目设计文档和技术方案</li></ul><p><strong>下午（2h）：项目结构搭建</strong></p><ul><li>创建项目骨架</li><li>配置开发环境</li><li>搭建基础架构</li><li>🔴 <strong>必须完成</strong>：项目可以正常运行</li></ul><p><strong>晚上（1h）：核心模块开发</strong></p><ul><li>开始实现核心功能</li><li>🟡 <strong>有余力再做</strong>：完成第一个核心模块</li></ul><hr><h3 id="day-37-周二" tabindex="-1">Day 37（周二） <a class="header-anchor" href="#day-37-周二" aria-label="Permalink to &quot;Day 37（周二）&quot;">​</a></h3><p><strong>上午（2h）：核心功能开发</strong></p><ul><li>按照计划开发核心功能</li><li>可能是RAG部分，也可能是Agent部分</li><li>🔴 <strong>必须完成</strong>：核心功能可以跑通</li></ul><p><strong>下午（2h）：功能完善</strong></p><ul><li>添加错误处理</li><li>优化用户体验</li><li>🔴 <strong>必须完成</strong>：功能基本完整</li></ul><p><strong>晚上（1h）：继续开发</strong></p><ul><li>继续完善项目功能</li><li><strong>产出</strong>：项目完成度达到70%以上</li></ul><hr><h3 id="day-38-周三" tabindex="-1">Day 38（周三） <a class="header-anchor" href="#day-38-周三" aria-label="Permalink to &quot;Day 38（周三）&quot;">​</a></h3><p><strong>上午（2h）：LlamaIndex入门</strong></p><ul><li>LlamaIndex是什么，和LangChain的区别</li><li>LlamaIndex的核心概念</li><li>安装和Hello World</li><li>🔴 <strong>必须完成</strong>：能安装并使用LlamaIndex</li></ul><p><strong>下午（2h）：LlamaIndex RAG</strong></p><ul><li>用LlamaIndex实现RAG</li><li>对比LangChain和LlamaIndex的实现</li><li>🔴 <strong>必须完成</strong>：用LlamaIndex实现一个RAG应用</li></ul><p><strong>晚上（1h）：项目整合</strong></p><ul><li>尝试在项目中使用LlamaIndex</li><li>🟡 <strong>有余力再做</strong>：对比两种实现的优劣</li></ul><hr><h3 id="day-39-周四" tabindex="-1">Day 39（周四） <a class="header-anchor" href="#day-39-周四" aria-label="Permalink to &quot;Day 39（周四）&quot;">​</a></h3><p><strong>上午（2h）：项目收尾</strong></p><ul><li>完成项目的剩余功能</li><li>进行整体测试</li><li>🔴 <strong>必须完成</strong>：项目功能完整可运行</li></ul><p><strong>下午（2h）：项目优化</strong></p><ul><li>性能优化</li><li>代码优化</li><li>添加文档</li><li>🔴 <strong>必须完成</strong>：项目代码整洁，有README</li></ul><p><strong>晚上（1h）：准备演示</strong></p><ul><li>准备项目演示</li><li>写好项目介绍和使用说明</li><li><strong>产出</strong>：准备好可以展示的项目</li></ul><hr><h3 id="day-40-周五" tabindex="-1">Day 40（周五） <a class="header-anchor" href="#day-40-周五" aria-label="Permalink to &quot;Day 40（周五）&quot;">​</a></h3><p><strong>上午（2h）：项目演示与复盘</strong></p><ul><li>完整演示项目功能</li><li>总结项目中的问题和解决方案</li><li>🔴 <strong>必须完成</strong>：能流畅演示项目</li></ul><p><strong>下午（2h）：简历素材整理</strong></p><ul><li>把项目整理成简历可用的素材</li><li>写项目介绍（要能讲清楚项目解决了什么问题、怎么实现的）</li><li>🔴 <strong>必须完成</strong>：完成至少1个项目的简历描述</li></ul><p><strong>晚上（1h）：第六周复盘</strong></p><ul><li>整理所有项目代码和文档</li><li><strong>产出</strong>：更新GitHub，更新简历素材库</li></ul><hr><h3 id="day-41-周六-⚡-补漏日" tabindex="-1">Day 41（周六）⚡ 补漏日 <a class="header-anchor" href="#day-41-周六-⚡-补漏日" aria-label="Permalink to &quot;Day 41（周六）⚡ 补漏日&quot;">​</a></h3><p><strong>上午（2h）：项目收尾</strong></p><ul><li>确保项目完全可用</li><li>解决所有已知问题</li></ul><p><strong>下午（2h）：面试准备</strong></p><ul><li>开始看一些AI面试题</li><li>了解常见的面试问题类型</li></ul><hr><h3 id="day-42-周日-休息日" tabindex="-1">Day 42（周日）休息日 <a class="header-anchor" href="#day-42-周日-休息日" aria-label="Permalink to &quot;Day 42（周日）休息日&quot;">​</a></h3><p>休息日。可以开始关注一些AI公司的招聘信息，了解市场需求。</p><hr><h2 id="第7周-简历优化-作品集准备" tabindex="-1">第7周：简历优化 + 作品集准备 <a class="header-anchor" href="#第7周-简历优化-作品集准备" aria-label="Permalink to &quot;第7周：简历优化 + 作品集准备&quot;">​</a></h2><p>本周目标是完成一份专业的AI开发者简历，并准备好作品集。</p><h3 id="day-43-周一" tabindex="-1">Day 43（周一） <a class="header-anchor" href="#day-43-周一" aria-label="Permalink to &quot;Day 43（周一）&quot;">​</a></h3><p><strong>上午（2h）：简历结构设计</strong></p><ul><li>AI开发者简历的标准结构</li><li>技术技能怎么写</li><li>项目经验怎么描述</li><li>🔴 <strong>必须完成</strong>：完成简历初稿</li></ul><p><strong>下午（2h）：简历内容填充</strong></p><ul><li>填充教育背景</li><li>填充工作/实习经历</li><li>填充技术技能</li><li>🔴 <strong>必须完成</strong>：简历各板块内容完整</li></ul><p><strong>晚上（1h）：项目描述撰写</strong></p><ul><li>用STAR法则描述项目</li><li>量化项目成果（&quot;提升了30%的检索准确率&quot;）</li><li><strong>产出</strong>：完成至少2个项目的详细描述</li></ul><hr><h3 id="day-44-周二" tabindex="-1">Day 44（周二） <a class="header-anchor" href="#day-44-周二" aria-label="Permalink to &quot;Day 44（周二）&quot;">​</a></h3><p><strong>上午（2h）：简历深度打磨</strong></p><ul><li>关键词优化（针对ATS系统）</li><li>量化成果的表达</li><li>技术栈的准确描述</li><li>🔴 <strong>必须完成</strong>：简历可以通过ATS筛选</li></ul><p><strong>下午（2h）：作品集准备</strong></p><ul><li>GitHub主页美化</li><li>README模板</li><li>项目列表整理</li><li>🔴 <strong>必须完成</strong>：GitHub主页整洁专业</li></ul><p><strong>晚上（1h）：技术博客</strong></p><ul><li>考虑是否写技术博客</li><li>🟡 <strong>有余力再做</strong>：开始写第一篇博客</li></ul><hr><h3 id="day-45-周三" tabindex="-1">Day 45（周三） <a class="header-anchor" href="#day-45-周三" aria-label="Permalink to &quot;Day 45（周三）&quot;">​</a></h3><p><strong>上午（2h）：面试题库准备</strong></p><ul><li>RAG相关面试题</li><li>Agent相关面试题</li><li>LangChain/LlamaIndex相关面试题</li><li>🔴 <strong>必须完成</strong>：整理常见面试题库</li></ul><p><strong>下午（2h）：面试题深度准备</strong></p><ul><li>每道题准备答案要点</li><li>练习口头表达</li><li>🔴 <strong>必须完成</strong>：能回答70%以上的常见面试题</li></ul><p><strong>晚上（1h）：继续准备</strong></p><ul><li>继续刷面试题</li><li>🟡 <strong>有余力再做</strong>：找AI模拟面试</li></ul><hr><h3 id="day-46-周四" tabindex="-1">Day 46（周四） <a class="header-anchor" href="#day-46-周四" aria-label="Permalink to &quot;Day 46（周四）&quot;">​</a></h3><p><strong>上午（2h）：项目细节深挖</strong></p><ul><li>准备好可能被问的项目问题</li><li>能回答&quot;项目难点在哪&quot;&quot;怎么解决的&quot;</li><li>🔴 <strong>必须完成</strong>：对自己的项目了如指掌</li></ul><p><strong>下午（2h）：系统设计问题</strong></p><ul><li>准备系统设计类问题</li><li>RAG系统怎么设计</li><li>Agent系统怎么设计</li><li>🔴 <strong>必须完成</strong>：能画出RAG/Agent系统的架构图</li></ul><p><strong>晚上（1h）：模拟练习</strong></p><ul><li>自己对自己讲项目</li><li>练习自我介绍</li></ul><hr><h3 id="day-47-周五" tabindex="-1">Day 47（周五） <a class="header-anchor" href="#day-47-周五" aria-label="Permalink to &quot;Day 47（周五）&quot;">​</a></h3><p><strong>上午（2h）：行为面试准备</strong></p><ul><li>准备STAR法则回答</li><li>准备常见行为问题（优点、缺点、职业规划等）</li><li>🔴 <strong>必须完成</strong>：能流利回答常见行为问题</li></ul><p><strong>下午（2h）：薪资谈判准备</strong></p><ul><li>了解市场行情</li><li>准备谈薪资的策略</li><li>🟡 <strong>有余力再做</strong>：查一下目标公司的薪资范围</li></ul><p><strong>晚上（1h）：第七周复盘</strong></p><ul><li>整理所有准备材料</li><li><strong>产出</strong>：准备好完整的求职材料包</li></ul><hr><h3 id="day-48-周六-⚡-补漏日" tabindex="-1">Day 48（周六）⚡ 补漏日 <a class="header-anchor" href="#day-48-周六-⚡-补漏日" aria-label="Permalink to &quot;Day 48（周六）⚡ 补漏日&quot;">​</a></h3><p><strong>上午（2h）：查漏补缺</strong></p><ul><li>检查简历、面试题、项目描述</li><li>补上任何不完善的地方</li></ul><p><strong>下午（2h）：开始投递</strong></p><ul><li>在招聘网站注册账号</li><li>开始投递第一批简历</li><li>🟡 <strong>有余力再做</strong>：主动联系一些公司</li></ul><hr><h3 id="day-49-周日-休息日" tabindex="-1">Day 49（周日）休息日 <a class="header-anchor" href="#day-49-周日-休息日" aria-label="Permalink to &quot;Day 49（周日）休息日&quot;">​</a></h3><p>休息日。可以关注一些AI开发者社区，和同行交流。</p><hr><h2 id="第8周-面试实战-入职准备" tabindex="-1">第8周：面试实战 + 入职准备 <a class="header-anchor" href="#第8周-面试实战-入职准备" aria-label="Permalink to &quot;第8周：面试实战 + 入职准备&quot;">​</a></h2><p>本周目标是进行真实的面试实战，并做好入职准备。</p><h3 id="day-50-周一" tabindex="-1">Day 50（周一） <a class="header-anchor" href="#day-50-周一" aria-label="Permalink to &quot;Day 50（周一）&quot;">​</a></h3><p><strong>上午（2h）：开始投递简历</strong></p><ul><li>在Boss直聘、拉勾、猎聘等平台投递</li><li>关注AI公司官网的招聘信息</li><li>🔴 <strong>必须完成</strong>：完成至少10家公司的简历投递</li></ul><p><strong>下午（2h）：面试预约</strong></p><ul><li>跟进投递进度</li><li>预约面试时间</li><li>🔴 <strong>必须完成</strong>：约到至少3个面试</li></ul><p><strong>晚上（1h）：最后的复习</strong></p><ul><li>快速过一遍知识点</li><li>查漏补缺</li></ul><hr><h3 id="day-51-周二" tabindex="-1">Day 51（周二） <a class="header-anchor" href="#day-51-周二" aria-label="Permalink to &quot;Day 51（周二）&quot;">​</a></h3><p><strong>上午（2h）：面试实战（如果有的话）</strong></p><ul><li>参加预约的面试</li><li>记录面试问题</li><li>🔴 <strong>必须完成</strong>：无论结果如何，都从每次面试中学习</li></ul><p><strong>下午（2h）：面试复盘</strong></p><ul><li>分析今天面试的问题</li><li>总结被问到但没回答好的问题</li><li>查资料补上答案</li><li>🔴 <strong>必须完成</strong>：更新面试题库</li></ul><p><strong>晚上（1h）：继续投递</strong></p><ul><li>根据面试反馈调整简历</li><li>继续投递</li></ul><hr><h3 id="day-52-周三" tabindex="-1">Day 52（周三） <a class="header-anchor" href="#day-52-周三" aria-label="Permalink to &quot;Day 52（周三）&quot;">​</a></h3><p><strong>上午（2h）：技术面准备</strong></p><ul><li>刷算法题（重点是字符串、数组、图）</li><li>准备系统设计问题</li><li>🔴 <strong>必须完成</strong>：能完成简单算法题</li></ul><p><strong>下午（2h）：继续面试</strong></p><ul><li>参加更多面试</li><li>积累面试经验</li><li>🔴 <strong>必须完成</strong>：完成至少5次面试</li></ul><p><strong>晚上（1h）：offer比较</strong></p><ul><li>如果有offer，开始比较</li><li>考虑因素：薪资、发展、团队、技术栈</li></ul><hr><h3 id="day-53-周四" tabindex="-1">Day 53（周四） <a class="header-anchor" href="#day-53-周四" aria-label="Permalink to &quot;Day 53（周四）&quot;">​</a></h3><p><strong>上午（2h）：offer谈判</strong></p><ul><li>学会和HR谈薪资</li><li>了解自己的底线</li><li>🔴 <strong>必须完成</strong>：拿到至少1个offer</li></ul><p><strong>下午（2h）：背景调查准备</strong></p><ul><li>准备背景调查需要的材料</li><li>联系推荐人</li><li>🟡 <strong>有余力再做</strong>：准备入职材料</li></ul><p><strong>晚上（1h）：继续面试</strong></p><ul><li>继续面试其他公司</li><li>给自己更多选择</li></ul><hr><h3 id="day-54-周五" tabindex="-1">Day 54（周五） <a class="header-anchor" href="#day-54-周五" aria-label="Permalink to &quot;Day 54（周五）&quot;">​</a></h3><p><strong>上午（2h）：做出决定</strong></p><ul><li>比较所有offer</li><li>做出最终选择</li><li>🔴 <strong>必须完成</strong>：确定要去的公司</li></ul><p><strong>下午（2h）：offer确认</strong></p><ul><li>确认offer细节</li><li>谈薪资待遇</li><li>确认入职时间</li><li>🔴 <strong>必须完成</strong>：拿到满意的offer</li></ul><p><strong>晚上（1h）：第八周复盘</strong></p><ul><li>总结整个8周的学习</li><li>感谢帮助过你的人</li><li><strong>产出</strong>：写一篇8周学习总结</li></ul><hr><h3 id="day-55-周六-⚡-补漏日" tabindex="-1">Day 55（周六）⚡ 补漏日 <a class="header-anchor" href="#day-55-周六-⚡-补漏日" aria-label="Permalink to &quot;Day 55（周六）⚡ 补漏日&quot;">​</a></h3><p><strong>上午（2h）：入职准备</strong></p><ul><li>准备入职材料</li><li>了解新公司的技术栈，提前学习</li><li>🟡 <strong>有余力再做</strong>：读一读公司公开的技术博客</li></ul><p><strong>下午（2h）：心理准备</strong></p><ul><li>调整心态，准备迎接新挑战</li><li>保持学习的心态</li></ul><hr><h3 id="day-56-周日-休息日-新起点" tabindex="-1">Day 56（周日）休息日 + 新起点 <a class="header-anchor" href="#day-56-周日-休息日-新起点" aria-label="Permalink to &quot;Day 56（周日）休息日 + 新起点&quot;">​</a></h3><p>恭喜你完成8周入行计划！今天好好休息，为新征程做准备。</p><p><strong>这一天你可以：</strong></p><ul><li>和朋友庆祝一下</li><li>开始了解新公司的业务</li><li>规划入职后的学习计划</li><li>或者，只是单纯地休息一天</li></ul><hr><h2 id="附录d使用建议" tabindex="-1">附录D使用建议 <a class="header-anchor" href="#附录d使用建议" aria-label="Permalink to &quot;附录D使用建议&quot;">​</a></h2><h3 id="调整节奏" tabindex="-1">调整节奏 <a class="header-anchor" href="#调整节奏" aria-label="Permalink to &quot;调整节奏&quot;">​</a></h3><p>这份计划是按照&quot;每天5小时&quot;设计的。如果你时间更充裕，可以加快节奏；如果你时间紧张，可以拉长周期。关键是<strong>保持学习的连贯性</strong>，不要中断太久。</p><h3 id="记录进度" tabindex="-1">记录进度 <a class="header-anchor" href="#记录进度" aria-label="Permalink to &quot;记录进度&quot;">​</a></h3><p>建议每天记录自己的学习进度和遇到的问题。这样在复盘和补漏的时候能更有针对性。</p><h3 id="找到社群" tabindex="-1">找到社群 <a class="header-anchor" href="#找到社群" aria-label="Permalink to &quot;找到社群&quot;">​</a></h3><p>一个人学习容易懈怠。建议加入一些学习社群，和同行交流。有问题及时问，不要卡太久。</p><h3 id="保持弹性" tabindex="-1">保持弹性 <a class="header-anchor" href="#保持弹性" aria-label="Permalink to &quot;保持弹性&quot;">​</a></h3><p>计划赶不上变化是正常的。漏掉的内容在补漏日补上就行，不用焦虑。重要的是<strong>持续前进</strong>，而不是完美执行。</p><h3 id="入职不是终点" tabindex="-1">入职不是终点 <a class="header-anchor" href="#入职不是终点" aria-label="Permalink to &quot;入职不是终点&quot;">​</a></h3><p>找到工作只是入行的第一步。真正的挑战是入职后能不能快速成长、能不能产出价值。保持学习的心态，你会在这个领域越走越远。</p><hr><p><strong>祝你入行顺利！</strong></p>',432)])])}const y=i(n,[["render",o]]);export{d as __pageData,y as default};
